 21→	// Use a short-lived context so retries don't take forever.
 22→	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
 23→	defer cancel()
 24→
 25→	_, err := Connect(ctx, "postgres://nobody:nopass@127.0.0.1:1/nodb?connect_timeout=1")
 26→	if err == nil {
 27→		t.Fatal("expected error for unreachable host, got nil")
 28→	}
 29→}
