 50→
 51→func skipIfShortOrNoDB(t *testing.T) {
 52→	t.Helper()
 53→	if testing.Short() {
 54→		t.Skip("skipping integration test in -short mode")
 55→	}
 56→	if os.Getenv("DATABASE_URL") == "" {
 57→		t.Skip("skipping integration test: DATABASE_URL not set")
 58→	}
 59→}
