 61→func TestIntegrationConnect(t *testing.T) {
 62→	skipIfShortOrNoDB(t)
 63→
 64→	ctx := context.Background()
 65→	pool, err := Connect(ctx, os.Getenv("DATABASE_URL"))
 66→	if err != nil {
 67→		t.Fatalf("Connect failed: %v", err)
 68→	}
 69→	defer pool.Close()
 70→
 71→	var result int
 72→	if err := pool.QueryRow(ctx, "SELECT 1").Scan(&result); err != nil {
 73→		t.Fatalf("SELECT 1 failed: %v", err)
 74→	}
 75→	if result != 1 {
 76→		t.Fatalf("expected 1, got %d", result)
 77→	}
 78→}
 79→
 80→func TestIntegrationMigrations(t *testing.T) {
 81→	skipIfShortOrNoDB(t)
 82→
 83→	ctx := context.Background()
 84→	dbURL := os.Getenv("DATABASE_URL")
 85→
 86→	if err := MigrateUp(ctx, dbURL); err != nil {
 87→		t.Fatalf("MigrateUp failed: %v", err)
 88→	}
 89→
 90→	// Verify tables exist by connecting and querying information_schema.
 91→	pool, err := Connect(ctx, dbURL)
 92→	if err != nil {
 93→		t.Fatalf("Connect failed: %v", err)
 94→	}
 95→	defer pool.Close()
 96→
 97→	tables := []string{"users", "items", "mcp_clients", "audit_log"}
 98→	for _, table := range tables {
 99→		var exists bool
100→		err := pool.QueryRow(ctx,
101→			"SELECT EXISTS(SELECT 1 FROM information_schema.tables WHERE table_name = $1)",
102→			table,
103→		).Scan(&exists)
104→		if err != nil {
105→			t.Fatalf("checking table %s: %v", table, err)
106→		}
107→		if !exists {
108→			t.Errorf("table %s does not exist after MigrateUp", table)
109→		}
110→	}
111→
112→	if err := MigrateDown(ctx, dbURL); err != nil {
113→		t.Fatalf("MigrateDown failed: %v", err)
114→	}
115→}
