package db

import (
	"context"
	"database/sql"
	"fmt"
	"log/slog"
	"time"

	"github.com/jackc/pgx/v5/pgxpool"
	_ "github.com/jackc/pgx/v5/stdlib"
	"github.com/ketang/flotsam/api/migrations"
	"github.com/pressly/goose/v3"
)

const maxConnectAttempts = 3

// Connect creates a pgxpool.Pool, pings the database, and returns the pool.
// It retries up to maxConnectAttempts times with exponential backoff.
func Connect(ctx context.Context, databaseURL string) (*pgxpool.Pool, error) {
	cfg, err := pgxpool.ParseConfig(databaseURL)
	if err != nil {
		return nil, fmt.Errorf("db: failed to parse database URL: %w", err)
	}

	var pool *pgxpool.Pool
	for attempt := 1; attempt <= maxConnectAttempts; attempt++ {
		pool, err = pgxpool.NewWithConfig(ctx, cfg)
		if err != nil {
			slog.Warn("db: connect attempt failed", "attempt", attempt, "error", err)
			time.Sleep(time.Duration(attempt) * time.Second)
			continue
		}

		if err = pool.Ping(ctx); err != nil {
			pool.Close()
			slog.Warn("db: ping attempt failed", "attempt", attempt, "error", err)
			time.Sleep(time.Duration(attempt) * time.Second)
			continue
		}

		stat := pool.Stat()
		slog.Info("db: connected",
			"attempt", attempt,
			"max_conns", stat.MaxConns(),
		)
		return pool, nil
	}

	return nil, fmt.Errorf("db: failed to connect after %d attempts: %w", maxConnectAttempts, err)
}

// newProvider creates a goose Provider instance using the embedded migrations.
func newProvider(db *sql.DB) (*goose.Provider, error) {
	provider, err := goose.NewProvider(goose.DialectPostgres, db, migrations.FS)
	if err != nil {
		return nil, fmt.Errorf("migrate: create provider: %w", err)
	}
	return provider, nil
}

// MigrateUp runs all pending goose UP migrations embedded in the binary.
func MigrateUp(ctx context.Context, databaseURL string) error {
	slog.Info("migrate: running up migrations")
	start := time.Now()

	db, err := sql.Open("pgx", databaseURL)
	if err != nil {
		return fmt.Errorf("migrate: failed to open db: %w", err)
	}
	defer db.Close() //nolint:errcheck // best-effort close

	provider, err := newProvider(db)
	if err != nil {
		return err
	}

	results, err := provider.Up(ctx)
	if err != nil {
		slog.Error("migrate: up failed", "error", err, "duration_ms", time.Since(start).Milliseconds())
		return fmt.Errorf("migrate: up: %w", err)
	}

	slog.Info("migrate: up completed",
		"applied", len(results),
		"duration_ms", time.Since(start).Milliseconds(),
	)
	return nil
}

// MigrateDown rolls back the most recent goose migration.
func MigrateDown(ctx context.Context, databaseURL string) error {
	slog.Info("migrate: rolling back last migration")
	start := time.Now()

	db, err := sql.Open("pgx", databaseURL)
	if err != nil {
		return fmt.Errorf("migrate: failed to open db: %w", err)
	}
	defer db.Close() //nolint:errcheck // best-effort close

	provider, err := newProvider(db)
	if err != nil {
		return err
	}

	result, err := provider.Down(ctx)
	if err != nil {
		slog.Error("migrate: down failed", "error", err, "duration_ms", time.Since(start).Milliseconds())
		return fmt.Errorf("migrate: down: %w", err)
	}

	if result != nil {
		slog.Info("migrate: down completed",
			"rolled_back", result.Source.Path,
			"duration_ms", time.Since(start).Milliseconds(),
		)
	} else {
		slog.Info("migrate: no migrations to roll back")
	}
	return nil
}

