package db

import (
	"context"
	"os"
	"testing"
	"time"
)

func TestConnect_InvalidURL(t *testing.T) {
	t.Parallel()
	ctx := context.Background()
	_, err := Connect(ctx, "not-a-valid-url")
	if err == nil {
		t.Fatal("expected error for invalid URL, got nil")
	}
}

func TestConnect_Unreachable(t *testing.T) {
	t.Parallel()
	// Use a short-lived context so retries don't take forever.
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	_, err := Connect(ctx, "postgres://nobody:nopass@127.0.0.1:1/nodb?connect_timeout=1")
	if err == nil {
		t.Fatal("expected error for unreachable host, got nil")
	}
}

func TestMigrateUp_InvalidURL(t *testing.T) {
	t.Parallel()
	ctx := context.Background()
	err := MigrateUp(ctx, "not-a-valid-url")
	if err == nil {
		t.Fatal("expected error for invalid URL, got nil")
	}
}

func TestMigrateDown_InvalidURL(t *testing.T) {
	t.Parallel()
	ctx := context.Background()
	err := MigrateDown(ctx, "not-a-valid-url")
	if err == nil {
		t.Fatal("expected error for invalid URL, got nil")
	}
}

// --- Integration tests (require a running database) ---

func skipIfShortOrNoDB(t *testing.T) {
	t.Helper()
	if testing.Short() {
		t.Skip("skipping integration test in -short mode")
	}
	if os.Getenv("DATABASE_URL") == "" {
		t.Skip("skipping integration test: DATABASE_URL not set")
	}
}

func TestIntegrationConnect(t *testing.T) {
	skipIfShortOrNoDB(t)

	ctx := context.Background()
	pool, err := Connect(ctx, os.Getenv("DATABASE_URL"))
	if err != nil {
		t.Fatalf("Connect failed: %v", err)
	}
	defer pool.Close()

	var result int
	if err := pool.QueryRow(ctx, "SELECT 1").Scan(&result); err != nil {
		t.Fatalf("SELECT 1 failed: %v", err)
	}
	if result != 1 {
		t.Fatalf("expected 1, got %d", result)
	}
}

func TestIntegrationMigrations(t *testing.T) {
	skipIfShortOrNoDB(t)

	ctx := context.Background()
	dbURL := os.Getenv("DATABASE_URL")

	if err := MigrateUp(ctx, dbURL); err != nil {
		t.Fatalf("MigrateUp failed: %v", err)
	}

	// Verify tables exist by connecting and querying information_schema.
	pool, err := Connect(ctx, dbURL)
	if err != nil {
		t.Fatalf("Connect failed: %v", err)
	}
	defer pool.Close()

	tables := []string{"users", "items", "mcp_clients", "audit_log"}
	for _, table := range tables {
		var exists bool
		err := pool.QueryRow(ctx,
			"SELECT EXISTS(SELECT 1 FROM information_schema.tables WHERE table_name = $1)",
			table,
		).Scan(&exists)
		if err != nil {
			t.Fatalf("checking table %s: %v", table, err)
		}
		if !exists {
			t.Errorf("table %s does not exist after MigrateUp", table)
		}
	}

	if err := MigrateDown(ctx, dbURL); err != nil {
		t.Fatalf("MigrateDown failed: %v", err)
	}
}

-- +goose Up
-- +goose StatementBegin

-- Extensions
CREATE EXTENSION IF NOT EXISTS vector;
CREATE EXTENSION IF NOT EXISTS pg_trgm;

-- Enum types
CREATE TYPE item_type AS ENUM (
    'bookmark', 'voice_note', 'text_note', 'drive_doc', 'highlight', 'file'
);

CREATE TYPE item_status AS ENUM (
    'pending', 'processing', 'ready', 'error'
);

CREATE TYPE sensitivity_level AS ENUM (
    'public', 'normal', 'sensitive', 'private'
);

-- Users
CREATE TABLE users (
    id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    email         TEXT UNIQUE NOT NULL,
    display_name  TEXT,
    password_hash TEXT,
    auth_provider TEXT DEFAULT 'local',
    auth_subject  TEXT,
    settings      JSONB NOT NULL DEFAULT '{}',
    created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Items (unified content table)
CREATE TABLE items (
    id            UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    owner_id      UUID NOT NULL REFERENCES users(id),
    type          item_type NOT NULL,
    status        item_status NOT NULL DEFAULT 'pending',
    sensitivity   sensitivity_level NOT NULL DEFAULT 'normal',
    title         TEXT,
    content_text  TEXT,
    content_url   TEXT,
    embedding     vector(1536),
    search_vector tsvector GENERATED ALWAYS AS (
        setweight(to_tsvector('english', coalesce(title, '')), 'A') ||
        setweight(to_tsvector('english', coalesce(content_text, '')), 'B')
    ) STORED,
    tags          TEXT[] DEFAULT '{}',
    metadata      JSONB NOT NULL DEFAULT '{}',
    auto_metadata JSONB NOT NULL DEFAULT '{}',
    source        TEXT NOT NULL,
    source_url    TEXT,
    created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at    TIMESTAMPTZ NOT NULL DEFAULT now(),
    captured_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Items indexes
CREATE INDEX idx_items_owner ON items(owner_id);
CREATE INDEX idx_items_type ON items(owner_id, type);
CREATE INDEX idx_items_created ON items(owner_id, created_at DESC);
CREATE INDEX idx_items_tags ON items USING GIN(tags);
CREATE INDEX idx_items_metadata ON items USING GIN(metadata);
CREATE INDEX idx_items_search ON items USING GIN(search_vector);
CREATE INDEX idx_items_embedding ON items USING ivfflat(embedding vector_cosine_ops) WITH (lists = 100);
CREATE INDEX idx_items_sensitivity ON items(owner_id, sensitivity);

-- MCP clients
CREATE TABLE mcp_clients (
    id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    owner_id          UUID NOT NULL REFERENCES users(id),
    name              TEXT NOT NULL,
    api_key_hash      TEXT NOT NULL,
    permissions       JSONB NOT NULL DEFAULT '{}',
    requires_approval TEXT[] DEFAULT '{}',
    active            BOOLEAN NOT NULL DEFAULT true,
    last_used_at      TIMESTAMPTZ,
    created_at        TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Audit log
CREATE TABLE audit_log (
    id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    user_id          UUID NOT NULL REFERENCES users(id),
    client_id        UUID REFERENCES mcp_clients(id),
    action           TEXT NOT NULL,
    resource_type    TEXT,
    resource_id      UUID,
    request          JSONB,
    response_summary JSONB,
    approved         BOOLEAN,
    created_at       TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Trigger function: auto-update updated_at
CREATE OR REPLACE FUNCTION set_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = now();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_users_updated_at
    BEFORE UPDATE ON users
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

CREATE TRIGGER trg_items_updated_at
    BEFORE UPDATE ON items
    FOR EACH ROW EXECUTE FUNCTION set_updated_at();

-- +goose StatementEnd

-- +goose Down
-- +goose StatementBegin

DROP TRIGGER IF EXISTS trg_items_updated_at ON items;
DROP TRIGGER IF EXISTS trg_users_updated_at ON users;
DROP FUNCTION IF EXISTS set_updated_at();

DROP TABLE IF EXISTS audit_log;
DROP TABLE IF EXISTS mcp_clients;
DROP TABLE IF EXISTS items;
DROP TABLE IF EXISTS users;

DROP TYPE IF EXISTS sensitivity_level;
DROP TYPE IF EXISTS item_status;
DROP TYPE IF EXISTS item_type;

DROP EXTENSION IF EXISTS pg_trgm;
DROP EXTENSION IF EXISTS vector;

-- +goose StatementEnd

package main

import (
	"context"
	"log/slog"
	"os"
	"os/signal"
	"syscall"

	"github.com/joho/godotenv"

	"github.com/ketang/flotsam/api/internal/auth"
	"github.com/ketang/flotsam/api/internal/config"
	"github.com/ketang/flotsam/api/internal/db"
	"github.com/ketang/flotsam/api/internal/router"
	"github.com/ketang/flotsam/api/internal/server"
	"github.com/ketang/flotsam/api/internal/version"
)

func main() {
	// 1. Load .env (no-op if file is absent — dev convenience only)
	_ = godotenv.Load()

	// 2. Parse and validate configuration
	cfg, err := config.Load()
	if err != nil {
		slog.Error("failed to load config", "error", err)
		os.Exit(1)
	}

	// 3. Configure structured logger
	slog.SetDefault(slog.New(cfg.LogHandler()))
	slog.Info("starting flotsam api",
		"version", version.Version,
		"build_time", version.BuildTime,
		"env", cfg.Env,
	)

	// 4. Connect to database
	ctx := context.Background()
	pool, err := db.Connect(ctx, cfg.DatabaseURL)
	if err != nil {
		slog.Error("failed to connect to database", "error", err)
		os.Exit(1) //nolint:gocritic // fatal startup error
	}
	defer pool.Close()

	// 5. Initialize auth validator
	validator := auth.NewHMACValidator(cfg.JWTSecret)
	slog.Info("auth: using HS256 JWT validator")

	// 6. Build router
	r := router.New(router.Deps{
		Config:    cfg,
		Pool:      pool,
		Validator: validator,
	})

	// 7. Start HTTP server
	srv := server.New(cfg.Addr(), r)

	sigCh := make(chan os.Signal, 1)
	signal.Notify(sigCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		slog.Info("server: listening", "addr", cfg.Addr())
		if err := srv.Start(); err != nil {
			slog.Info("server: stopped", "reason", err)
		}
	}()

	// 8. Block until signal received
	sig := <-sigCh
	slog.Info("signal received", "signal", sig)

	// 9. Graceful shutdown
	shutdownCtx, cancel := context.WithTimeout(context.Background(), cfg.ShutdownTimeout)
	defer cancel()

	slog.Info("server: shutting down", "timeout", cfg.ShutdownTimeout)
	if err := srv.Shutdown(shutdownCtx); err != nil {
		slog.Error("server: shutdown error", "error", err)
		os.Exit(1)
	}
	slog.Info("server: shutdown complete")
}

