package testutil

import (
	"context"
	"fmt"
	"sync"
	"testing"

	"github.com/jackc/pgx/v5/pgxpool"
	"github.com/testcontainers/testcontainers-go"
	"github.com/testcontainers/testcontainers-go/modules/postgres"
	"github.com/testcontainers/testcontainers-go/wait"

	"github.com/ketang/flotsam/api/internal/db"
)

var (
	sharedDSN  string
	sharedOnce sync.Once
	sharedErr  error
)

// startContainer launches a pgvector-enabled PostgreSQL container and returns
// the connection string. The container is cached per test binary via sync.Once
// so all tests in a package share the same instance.
func startContainer() (string, error) {
	sharedOnce.Do(func() {
		ctx := context.Background()

		ctr, err := postgres.Run(ctx,
			"pgvector/pgvector:pg16",
			postgres.WithDatabase("flotsam_test"),
			postgres.WithUsername("test"),
			postgres.WithPassword("test"),
			testcontainers.WithWaitStrategy(
				wait.ForLog("database system is ready to accept connections").
					WithOccurrence(2),
			),
		)
		if err != nil {
			sharedErr = fmt.Errorf("testutil: start container: %w", err)
			return
		}

		dsn, err := ctr.ConnectionString(ctx, "sslmode=disable")
		if err != nil {
			sharedErr = fmt.Errorf("testutil: connection string: %w", err)
			return
		}

		if err := db.MigrateUp(ctx, dsn); err != nil {
			sharedErr = fmt.Errorf("testutil: migrate up: %w", err)
			return
		}

		sharedDSN = dsn
	})
	return sharedDSN, sharedErr
}

// TestDB creates a PostgreSQL container with pgvector, runs migrations,
// and returns a connection pool. The container is shared across all tests
// in the package; the pool is closed when the test completes.
//
// Skips the test in -short mode (no Docker required for unit tests).
func TestDB(t *testing.T) *pgxpool.Pool {
	t.Helper()

	if testing.Short() {
		t.Skip("skipping: requires Docker")
	}

	dsn, err := startContainer()
	if err != nil {
		t.Fatalf("testutil: start container: %v", err)
	}

	ctx := context.Background()
	pool, err := pgxpool.New(ctx, dsn)
	if err != nil {
		t.Fatalf("testutil: connect pool: %v", err)
	}

	t.Cleanup(func() {
		pool.Close()
	})

	return pool
}

// TestDBWithSeed creates a test database and populates it with seed data.
// Each call inserts fresh seed data, so callers should be aware of
// accumulating rows if sharing the same container across tests.
func TestDBWithSeed(t *testing.T) *pgxpool.Pool {
	t.Helper()

	pool := TestDB(t)

	ctx := context.Background()
	if err := SeedAll(ctx, pool); err != nil {
		t.Fatalf("testutil: seed: %v", err)
	}

	return pool
}

