package testutil

import (
	"context"
	"testing"
)

func TestIntegrationTestDB(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping: requires Docker")
	}

	pool := TestDB(t)
	ctx := context.Background()

	var result int
	if err := pool.QueryRow(ctx, "SELECT 1").Scan(&result); err != nil {
		t.Fatalf("SELECT 1 failed: %v", err)
	}
	if result != 1 {
		t.Fatalf("expected 1, got %d", result)
	}
}

func TestIntegrationTestDBWithSeed(t *testing.T) {
	if testing.Short() {
		t.Skip("skipping: requires Docker")
	}

	pool := TestDBWithSeed(t)
	ctx := context.Background()

	// Verify row counts per table.
	checks := []struct {
		table   string
		minRows int
	}{
		{"users", 3},
		{"items", 9},       // 9 items per user × 3 users = 27 minimum
		{"mcp_clients", 2}, // 2 clients for first user
		{"audit_log", 6},   // 6 entries
	}

	for _, c := range checks {
		var count int
		err := pool.QueryRow(ctx, "SELECT COUNT(*) FROM "+c.table).Scan(&count)
		if err != nil {
			t.Fatalf("count %s: %v", c.table, err)
		}
		if count < c.minRows {
			t.Errorf("%s: expected >= %d rows, got %d", c.table, c.minRows, count)
		}
	}
}

