package db

import (
	"context"
	"os"
	"testing"
	"time"
)

func TestConnect_InvalidURL(t *testing.T) {
	t.Parallel()
	ctx := context.Background()
	_, err := Connect(ctx, "not-a-valid-url")
	if err == nil {
		t.Fatal("expected error for invalid URL, got nil")
	}
}

func TestConnect_Unreachable(t *testing.T) {
	t.Parallel()
	// Use a short-lived context so retries don't take forever.
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	_, err := Connect(ctx, "postgres://nobody:nopass@127.0.0.1:1/nodb?connect_timeout=1")
	if err == nil {
		t.Fatal("expected error for unreachable host, got nil")
	}
}

func TestMigrateUp_InvalidURL(t *testing.T) {
	t.Parallel()
	ctx := context.Background()
	err := MigrateUp(ctx, "not-a-valid-url")
	if err == nil {
		t.Fatal("expected error for invalid URL, got nil")
	}
}

func TestMigrateDown_InvalidURL(t *testing.T) {
	t.Parallel()
	ctx := context.Background()
	err := MigrateDown(ctx, "not-a-valid-url")
	if err == nil {
		t.Fatal("expected error for invalid URL, got nil")
	}
}

// --- Integration tests (require a running database) ---

func skipIfShortOrNoDB(t *testing.T) {
	t.Helper()
	if testing.Short() {
		t.Skip("skipping integration test in -short mode")
	}
	if os.Getenv("DATABASE_URL") == "" {
		t.Skip("skipping integration test: DATABASE_URL not set")
	}
}

// getTestPool returns a pool from testcontainers when DATABASE_URL is unset.
// Falls back to skipping if Docker is also unavailable.
func getTestPool(t *testing.T) {
	t.Helper()
	if testing.Short() {
		t.Skip("skipping integration test in -short mode")
	}
}

func TestIntegrationConnect_Testcontainer(t *testing.T) {
	getTestPool(t)
	if os.Getenv("DATABASE_URL") != "" {
		t.Skip("DATABASE_URL is set; use TestIntegrationConnect instead")
	}

	pool := testutil.TestDB(t)

	var result int
	if err := pool.QueryRow(context.Background(), "SELECT 1").Scan(&result); err != nil {
		t.Fatalf("SELECT 1 failed: %v", err)
	}
	if result != 1 {
		t.Fatalf("expected 1, got %d", result)
	}
}

func TestIntegrationMigrations_Testcontainer(t *testing.T) {
	getTestPool(t)
	if os.Getenv("DATABASE_URL") != "" {
		t.Skip("DATABASE_URL is set; use TestIntegrationMigrations instead")
	}

	pool := testutil.TestDB(t)
	ctx := context.Background()

	tables := []string{"users", "items", "mcp_clients", "audit_log"}
	for _, table := range tables {
		var exists bool
		err := pool.QueryRow(ctx,
			"SELECT EXISTS(SELECT 1 FROM information_schema.tables WHERE table_name = $1)",
			table,
		).Scan(&exists)
		if err != nil {
			t.Fatalf("checking table %s: %v", table, err)
		}
		if !exists {
			t.Errorf("table %s does not exist after migrations", table)
		}
	}
}

func TestIntegrationConnect(t *testing.T) {
	skipIfShortOrNoDB(t)

	ctx := context.Background()
	pool, err := Connect(ctx, os.Getenv("DATABASE_URL"))
	if err != nil {
		t.Fatalf("Connect failed: %v", err)
	}
	defer pool.Close()

	var result int
	if err := pool.QueryRow(ctx, "SELECT 1").Scan(&result); err != nil {
		t.Fatalf("SELECT 1 failed: %v", err)
	}
	if result != 1 {
		t.Fatalf("expected 1, got %d", result)
	}
}

func TestIntegrationMigrations(t *testing.T) {
	skipIfShortOrNoDB(t)

	ctx := context.Background()
	dbURL := os.Getenv("DATABASE_URL")

	if err := MigrateUp(ctx, dbURL); err != nil {
		t.Fatalf("MigrateUp failed: %v", err)
	}

	// Verify tables exist by connecting and querying information_schema.
	pool, err := Connect(ctx, dbURL)
	if err != nil {
		t.Fatalf("Connect failed: %v", err)
	}
	defer pool.Close()

	tables := []string{"users", "items", "mcp_clients", "audit_log"}
	for _, table := range tables {
		var exists bool
		err := pool.QueryRow(ctx,
			"SELECT EXISTS(SELECT 1 FROM information_schema.tables WHERE table_name = $1)",
			table,
		).Scan(&exists)
		if err != nil {
			t.Fatalf("checking table %s: %v", table, err)
		}
		if !exists {
			t.Errorf("table %s does not exist after MigrateUp", table)
		}
	}

	if err := MigrateDown(ctx, dbURL); err != nil {
		t.Fatalf("MigrateDown failed: %v", err)
	}
}

